const body = $input.first().json.body || $input.first().json;
const session_id = body.session_id || null;
const user_message = body.message || '';

if (!user_message || user_message.trim() === '') {
  throw new Error('Message is required');
}

return [{
  json: {
    session_id: session_id,
    user_message: user_message.trim(),
    is_new_session: !session_id
  }
}];

// Merge session data from either create or load path
const item = $input.first().json;
return [{
  json: {
    session_id: item.session_id,
    original_query: item.original_query,
    questions_asked: item.questions_asked || [],
    answers_collected: item.answers_collected || [],
    status: item.status || 'questioning'
  }
}];

const session = $('Merge Session Data').first().json;
const userMessage = $('Parse Input').first().json.user_message;
const questionsAsked = session.questions_asked || [];
const answersCollected = session.answers_collected || [];
const status = session.status;
const originalQuery = session.original_query || '';

const isReport = userMessage.toLowerCase().includes('report') || userMessage.length > 200;

// If status is already 'searching' or 'done', or if a report is uploaded, skip to search
if (status === 'searching' || status === 'done' || isReport) {
  return [{ json: { ...session, userMessage, action: 'search', questionsAsked, answersCollected } }];
}

// If this is the first message (no questions asked yet), action = generate_questions
if (questionsAsked.length === 0) {
  return [{ json: { ...session, userMessage, action: 'generate_questions', questionsAsked, answersCollected } }];
}

// Save latest answer
const updatedAnswers = [...answersCollected, userMessage];

// 1. Must ask at least 2 questions (so if we only have 1 answer, we always ask the next question)
if (updatedAnswers.length < 2) {
  return [{ json: { ...session, userMessage, action: 'next_question', questionsAsked, answersCollected: updatedAnswers } }];
}

// 2. Must ask at most 3 questions (so if we have collected 3 answers, we always proceed to search)
if (updatedAnswers.length >= 3) {
  return [{ json: { ...session, userMessage, action: 'search', questionsAsked, answersCollected: updatedAnswers } }];
}

// 3. For 2 questions: Apply heuristic to decide if we should stop early or ask the 3rd question.
const fullText = (originalQuery + ' ' + updatedAnswers.join(' ')).toLowerCase();
const hasLocation = /boston|chicago|london|new york|houston|los angeles|miami|seattle|austin|san francisco|dallas|philadelphia|atlanta|denver/i.test(fullText);
const isDetailed = fullText.length > 150;

if (hasLocation || isDetailed) {
  return [{ json: { ...session, userMessage, action: 'search', questionsAsked, answersCollected: updatedAnswers } }];
}

// Otherwise, ask a 3rd question
return [{ json: { ...session, userMessage, action: 'next_question', questionsAsked, answersCollected: updatedAnswers } }];

const session = $input.first().json;
const questionsAsked = session.questionsAsked || [];
const answersCollected = session.answersCollected || [];
const originalQuery = session.original_query;

// Build conversation context for Cohere
let conversationContext = `Patient's original query: ${originalQuery}\n\n`;
for (let i = 0; i < questionsAsked.length; i++) {
  conversationContext += `Bot Question ${i+1}: ${questionsAsked[i]}\n`;
  if (answersCollected[i]) {
    conversationContext += `Patient Answer ${i+1}: ${answersCollected[i]}\n`;
  }
}

const isFirstQuestion = questionsAsked.length === 0;

const systemPrompt = `You are a medical assistant chatbot helping patients find the right doctor.
Your job is to ask targeted clarifying questions to understand the patient's medical needs.
Ask ONE specific question at a time. Be empathetic, clear, and professional.
Focus on: symptoms severity, duration, location preference, language preference, budget range, urgency level.
Only return the question text, nothing else.`;

const userPrompt = isFirstQuestion 
  ? `Patient query: "${originalQuery}"\n\nAsk the first clarifying question to better understand their medical need. Ask about their primary symptom or concern in more detail.`
  : `${conversationContext}\nBased on the conversation so far, ask the next most important clarifying question. Questions asked so far: ${questionsAsked.length}. Do not repeat previous questions.`;

return [{
  json: {
    session_id: session.session_id,
    original_query: originalQuery,
    questionsAsked,
    answersCollected,
    systemPrompt,
    userPrompt,
    action: session.action
  }
}];

const llmResponse = $input.first().json;
const buildData = $('Build Question Prompt').first().json;

// Extract question text from Groq/LLM response
let questionText = '';
try {
  questionText = llmResponse.choices?.[0]?.message?.content || 
                 llmResponse.message?.content?.[0]?.text || 
                 llmResponse.text || 
                 'Could you please provide more details about your medical concern?';
} catch(e) {
  questionText = 'Could you please provide more details about your medical concern?';
}

questionText = questionText.trim();

// Update questions_asked array
const updatedQuestions = [...buildData.questionsAsked, questionText];

return [{
  json: {
    session_id: buildData.session_id,
    original_query: buildData.original_query,
    updatedQuestions,
    updatedAnswers: buildData.answersCollected,
    questionText,
    questionsCount: updatedQuestions.length
  }
}];

const data = $('Extract Question Text').first().json;
const questionsCount = data.questionsCount;
const totalQuestions = 3;

return [{
  json: {
    success: true,
    session_id: data.session_id,
    type: 'question',
    question_number: questionsCount,
    total_questions: totalQuestions,
    progress: Math.round((questionsCount / totalQuestions) * 100),
    message: data.questionText,
    card: {
      type: 'question_card',
      title: `Question ${questionsCount} of ${totalQuestions}`,
      subtitle: 'Help us find your perfect doctor',
      content: data.questionText,
      progress_bar: Math.round((questionsCount / totalQuestions) * 100),
      original_query: data.original_query,
      badge: questionsCount === 1 ? 'Getting Started' : questionsCount >= 2 ? 'Almost Done!' : 'In Progress'
    }
  }
}];

const session = $input.first().json;
const originalQuery = session.original_query;
const questionsAsked = session.questionsAsked || [];
const answersCollected = session.answersCollected || [];

// Build rich context for embedding
let fullContext = `Medical Query: ${originalQuery}\n`;
for (let i = 0; i < questionsAsked.length; i++) {
  fullContext += `Q: ${questionsAsked[i]}\n`;
  if (answersCollected[i]) {
    fullContext += `A: ${answersCollected[i]}\n`;
  }
}

// Update DB status to searching
return [{
  json: {
    session_id: session.session_id,
    original_query: originalQuery,
    questionsAsked,
    answersCollected,
    fullContext: fullContext.trim()
  }
}];

const cohereData = $input.first().json;
const searchContext = $('Build Search Context').first().json;

// Extract embedding vector
let embedding = [];
try {
  embedding = cohereData.embeddings?.float?.[0] || cohereData.embeddings?.[0] || [];
} catch(e) {
  throw new Error('Failed to extract embedding from Cohere response');
}

if (embedding.length === 0) {
  throw new Error('Empty embedding returned from Cohere');
}

const embeddingStr = '[' + embedding.join(',') + ']';

return [{
  json: {
    session_id: searchContext.session_id,
    original_query: searchContext.original_query,
    questionsAsked: searchContext.questionsAsked,
    answersCollected: searchContext.answersCollected,
    fullContext: searchContext.fullContext,
    embeddingStr
  }
}];

const searchResults = $input.all();
const embedData = $('Extract Embedding Vector').first().json;

if (!searchResults || searchResults.length === 0) {
  return [{
    json: {
      session_id: embedData.session_id,
      original_query: embedData.original_query,
      fullContext: embedData.fullContext,
      doctors: [],
      hasResults: false
    }
  }];
}

const doctors = searchResults.map(item => item.json);

// Format doctors list for Cohere ranking prompt
const doctorsText = doctors.map((doc, i) => 
  `Doctor ${i+1}:\n` +
  `- Name: ${doc.name}\n` +
  `- Specialization: ${doc.specialization}\n` +
  `- Experience: ${doc.experience_years} years\n` +
  `- Location: ${doc.location}\n` +
  `- Languages: ${Array.isArray(doc.languages) ? doc.languages.join(', ') : doc.languages}\n` +
  `- Availability: ${doc.availability}\n` +
  `- Rating: ${doc.rating}/5\n` +
  `- Fee Range: ${doc.fee_range}\n` +
  `- Bio: ${doc.bio}\n` +
  `- Similarity Score: ${(doc.similarity_score * 100).toFixed(1)}%`
).join('\n\n');

return [{
  json: {
    session_id: embedData.session_id,
    original_query: embedData.original_query,
    fullContext: embedData.fullContext,
    doctors,
    doctorsText,
    hasResults: true
  }
}];

const llmResponse = $input.first().json;
const searchData = $('Process Search Results').first().json;

let rankingData = {};
try {
  let rawText = llmResponse.choices?.[0]?.message?.content || llmResponse.message?.content?.[0]?.text || llmResponse.text || '{}';
  // Strip markdown code blocks if present
  rawText = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  rankingData = JSON.parse(rawText);
} catch(e) {
  rankingData = {
    best_match_index: 0,
    match_reason: 'Best available match based on your medical needs.',
    confidence_score: 0.85,
    key_strengths: ['Relevant specialization', 'Strong experience', 'Good availability'],
    recommendation_note: 'This doctor is well-suited to address your medical needs.',
    report_summary: ''
  };
}

const bestIndex = rankingData.best_match_index || 0;
const bestDoctor = searchData.doctors[bestIndex] || searchData.doctors[0];
const allDoctors = searchData.doctors;

if (!bestDoctor) {
  return [{
    json: {
      success: false,
      session_id: searchData.session_id,
      type: 'no_results',
      message: 'No matching doctors found. Please refine your search.'
    }
  }];
}

// Build rich card output
const doctorCard = {
  type: 'doctor_card',
  best_match: {
    id: bestDoctor.id,
    name: bestDoctor.name,
    specialization: bestDoctor.specialization,
    experience_years: bestDoctor.experience_years,
    location: bestDoctor.location,
    languages: Array.isArray(bestDoctor.languages) ? bestDoctor.languages : [bestDoctor.languages],
    availability: bestDoctor.availability,
    rating: bestDoctor.rating,
    fee_range: bestDoctor.fee_range,
    bio: bestDoctor.bio,
    phone: bestDoctor.phone || null,
    email: bestDoctor.email || null,
    hospital_name: bestDoctor.hospital_name || null,
    profile_image_url: bestDoctor.profile_image_url || null,
    similarity_score: parseFloat((bestDoctor.similarity_score * 100).toFixed(1))
  },
  ai_analysis: {
    confidence_score: parseFloat((rankingData.confidence_score * 100).toFixed(1)),
    match_reason: rankingData.match_reason,
    key_strengths: rankingData.key_strengths || [],
    recommendation_note: rankingData.recommendation_note,
    report_summary: rankingData.report_summary || ''
  },
  other_options: allDoctors
    .filter((_, i) => i !== bestIndex)
    .slice(0, 3)
    .map(doc => ({
      id: doc.id,
      name: doc.name,
      specialization: doc.specialization,
      rating: doc.rating,
      location: doc.location,
      similarity_score: parseFloat((doc.similarity_score * 100).toFixed(1))
    }))
};

return [{
  json: {
    success: true,
    session_id: searchData.session_id,
    type: 'doctor_match',
    original_query: searchData.original_query,
    card: doctorCard
  }
}];

