UPDATE chat_sessions SET status = 'done' WHERE session_id = '{{ $json.session_id }}';

INSERT INTO session_messages (session_id, role, content, turn_number, created_at)
VALUES (
  '{{ $json.session_id }}',
  'bot',
  'Doctor match found: {{ $json.card.best_match.name.replace(/'/g, "''") }} - {{ $json.card.best_match.specialization.replace(/'/g, "''") }}',
  999,
  NOW()
);

